var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"사흘 전","JPN":"三日前","ENG":"Three days earlier","TWN":"三天前"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 22일 런던, <color=#ffd34c>베이커 가 211번지</color>","JPN":"1888年10月22日　ロンドン、<color=#ffd34c>ベーカー街211番地</color>","ENG":"October 22, 1888, London, <color=#ffd34c>211 Baker St.</color>","TWN":"1888年10月22日 倫敦, <color=#ffd34c>貝克街211號</color>"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인, 문틈에 무슨 편지가 껴있던데요?","JPN":"アバーライン、ドアの隙間に手紙が挟んでありましたよ？","ENG":"Abberline, there's some kind of letter wedged in the door gap.","TWN":"艾伯林，門縫裡夾著一封信。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"편지라고? 그럴 리가 없지 않나?","JPN":"手紙？　そんなはずあるまい。","ENG":"A letter? That's impossible.","TWN":"信？怎麼可能有信呢？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 아지트는 인식 저해가 걸려있다네. 평범한 사람은 인식할 수 없지.","JPN":"このアジトには認識阻害措置がされている。普通の人間は認識できない。","ENG":"This hideout is with a Curio to hinder people's perception. An ordinary person can't recognize it.","TWN":"這個安全屋有認知干擾。普通人是無法察覺的。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"더욱이 나한테 편지 같은 걸 보낼 사람도 없고 말이야.","JPN":"それに私に手紙を送るような人もいないしな。","ENG":"Furthermore, there is no one who would send me any letters.","TWN":"而且也沒有人會給我寄信。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"글쎄요, 당신 인간관계 같은 건 전혀 궁금하지 않거든요?","JPN":"さあ、あなたの人間関係とか全然興味ありませんけどね。","ENG":"Well, I'm not curious about your personal relationships.","TWN":"哼，我對你的社交關係一點都不感興趣。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"자, 보세요. 정말로 편지가 있었다고요.","JPN":"はい、どうぞ。本当に手紙があったんです。","ENG":"But look. There really is a letter here for you.","TWN":"看吧，真的有信。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐, 그 편지는……?","JPN":"待て、その手紙は……？","ENG":"Wait, this letter…?","TWN":"等等，那封信是……？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어디보자. 친애하는 벗에게…….","JPN":"どれどれ。親愛なる友へ……","ENG":"Let’s see here. To my dear friend...","TWN":"我看看——致我親愛的朋友……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"음? 이거 수취인이 당신이 아닌데요? 뭔가 잘못 온 편지가…… ","JPN":"うん？　これ、あなた宛てじゃありませんね？　どうやら住所が…… ","ENG":"Hmm? This wasn't sent to you. Guess it's a delivery mistake–","TWN":"嗯？這封信的收件人不是你啊？好像是寄錯的信……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"엇!?","JPN":"あっ！？","ENG":"Huh?","TWN":"呃？！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"크흠, 정정하지.","JPN":"コホン、訂正しよう。","ENG":"Ahem, I take it back.","TWN":"咳咳，我收回前言。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이건 나한테 온 편지가 맞아. 그리고 무척 오랫동안 기다리고 있었던 편지지.","JPN":"これは確かに私宛ての手紙だ。それも、長い間待ち望んでいた、な。","ENG":"This letter is for me. And it's a letter that I've been anticipating for a very long time.","TWN":"這是給我的信。也是我等待了很久的信。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흥……!","JPN":"ふんっ……！","ENG":"Hmph...!","TWN":"哼……！"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야가 될 때까지 안락의자에 틀어박혀 꿈쩍도 안 하더니, 이럴 때는 재빠르시군요.","JPN":"深夜になるまでアームチェアにずっと座ってビクともしなかったのに、こんな時は素早いんですね。","ENG":"You never get out of that armchair until it's late at night. But you're quick to snatch that away from me.","TWN":"一直窩在安樂椅上到深夜都不動，這種時候倒是挺快的嘛。"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 팬레터라도 되나요? 누구 편지인데 그래요?","JPN":"ファンレターか何かですか？　誰からの手紙なんですか？","ENG":"A fan letter of yours? Who's it from?","TWN":"是誰的信啊？粉絲信嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"사흘 뒤라…….","JPN":"三日後か……","ENG":"In three days...","TWN":"三天後啊……"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 결행일은 사흘 뒤인가?","JPN":"そうか、決行する日は三日後なのか。","ENG":"Right, so the day is going to be in three days.","TWN":"好，行動日是三天後嗎？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"결행일?","JPN":"決行する日？","ENG":"The day?","TWN":"行動日？"},"stage":{"bg":"ROOM_03","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완. 지금부터 내가 하는 이야기를 잘 기억하게.","JPN":"スワン。今から私の言うことをしっかりと覚えてほしい。","ENG":"Swan. Do not forget what I'm about to tell you right now.","TWN":"史旺。從現在開始，你要好好記住我說的話。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"무척 중요한 이야기니까 말이지.","JPN":"とても大事な話だからな。","ENG":"I can't stress how important it is.","TWN":"因為這是非常重要的事情。"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"중요한 이야기라고요?","JPN":"大事な話……ですか？","ENG":"Important?","TWN":"重要的事情？"},"stage":{"bg":"ROOM_03","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 25일 런던, <color=#ffd34c>황금 새벽회</color> 지하 사원","JPN":"1888年10月25日　ロンドン、<color=#ffd34c>黄金の暁団</color>地下寺院","ENG":"October 25, 1888, London, <color=#ffd34c>Golden Dawn</color> Underground Temple","TWN":"1888年10月25日 倫敦，<color=#ffd34c>黃金黎明會</color>地下神廟"},"stage":{"bg":"BLACK","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인 경위님, 모든 경관에게 마석탄 지급은 완료하였습니다.","JPN":"アバーライン警部補、すべての警官に魔石弾を支給しました。","ENG":"Lieutenant Abberline, we have supplied all officers with Mana bullets.","TWN":"艾伯林警官，所有警員的魔石彈都已發放完畢。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L49_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"지시만 내려 주시면 언제든 진입 가능합니다.","JPN":"指示を出してくだされば、いつでも突入可能です。","ENG":"We are ready to enter when you give us the orders.","TWN":"只要你下令，隨時可以進入。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"알겠네.","JPN":"わかった。","ENG":"Very well.","TWN":"知道了。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모리어티 교수, 이걸로 드디어 오랜 악연을 청산할 때가 왔군.","JPN":"モリアーティ教授、これでやっと長い腐れ縁を断ち切れる時が来たな。","ENG":"So, the time has come for me to finally settle this ill-fated relationship with Professor Moriarty.","TWN":"莫里蒂教授，終於到了清算我們舊怨的時候了。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모든 경관은 듣게!","JPN":"全警官は聞いたまえ！","ENG":"Attention all officers!","TWN":"所有警員聽令！"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나는 칙명을 받고, 이 사건을 담당하게 된 프레드릭 애버라인 경위라네!","JPN":"私は勅命を受け、この事件を担当することになったフレデリック・アバーライン警部補だ！","ENG":"I am Lieutenant Fredrick Abberline, the one in charge of the case by royal decree!","TWN":"我是奉命處理此案的弗雷德里克·艾伯林警官！"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네들도 잘 알고 있겠지?","JPN":"君たちもよく知っていることだろう。","ENG":"I'm sure you all know who I am.","TWN":"你們應該很清楚吧？"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"최근 심야의 살인마 사건으로 인해, 스코틀랜드 야드의 위상은 곤두박질치고 말았어.","JPN":"昨今の深夜の殺人鬼事件により、スコットランドヤードの威信は地に落ちてしまった。","ENG":"With the recent Midnight Killer cases, Scotland Yard's reputation has plummeted.","TWN":"最近由於午夜殺人魔事件，蘇格蘭場的聲譽一落千丈。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"한달 사이에 네 명의 여인이 희생되었고, 사회는 혼란에 빠졌으며.","JPN":"一ヵ月の間に四人の女性が犠牲になって、社会は混乱に陥り。","ENG":"In just one month, four women have fallen victim, and society is in chaos.","TWN":"一個月內有四名女子遇害，社會陷入了混亂。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"거리에선 시도 때도 없이 폭동이 일어나고 있고, 이젠 왕실까지 위협을 받고 있어.","JPN":"街では常に暴動が発生し、もはや王室までもが脅かされている。","ENG":"Riots are constantly breaking out on the streets, and now, even the royal family is being threatened.","TWN":"街上隨時隨地都在發生暴動，現在連王室都受到了威脅。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"다시 말해, 런던은 언제 광기의 안개에 삼켜져도 이상하지 않은 일촉즉발의 상황이야.","JPN":"つまりロンドンはいつ狂気の霧に飲み込まれてもおかしくない、一触即発の状況だ。","ENG":"In other words, London is on the verge of being engulfed by the fog of madness.","TWN":"換句話說，倫敦隨時可能被瘋狂的迷霧吞噬，局勢一觸即發。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그럼에도 자네들은 여기에 있네!","JPN":"だが、それでもなお、君たちはここにいる！","ENG":"Yet, you all stand here today!","TWN":"不過即便如此，你們還是在這裡啊！"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"아무리 손가락질당하고, 비웃음당하고, 모욕을 당할지라도……!","JPN":"いくら後ろ指を指され、嘲笑われ、侮辱されようとも……！","ENG":"No matter the blames, the sneers, and the insults you all received...!","TWN":"即使被指指點點，被嘲笑，被侮辱……！"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 자리에 있는 모든 경관은 마음속 신념을 꿋꿋이 지키며 이곳에 있네!","JPN":"己が信念を貫かんがために、ここに来たのだ！","ENG":"Every officer here has stood their ground and held on to their beliefs!","TWN":"在場的所有警官都堅定地守護著心中的信念，堅守在這裡！"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 지금, 이 순간! 비로소 자네들은 그 오명을 바로잡을 기회를 얻었어.","JPN":"そして今、この瞬間！　君たちはついにその汚名を返上するチャンスを得た。","ENG":"And now, in this moment! The opportunity has come to cleanse that shame.","TWN":"而現在，這一刻！你們終於有機會洗刷那汙名了。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자네들 한 사람, 한 사람의 신념으로써, 사건은 전환점을 맞이하게 되겠지.","JPN":"君たち一人一人の信念をもって、事件は転換点を迎えることとなるだろう。","ENG":"With each one of your beliefs, the case will reach a turning point.","TWN":"憑藉你們每個人的信念，事件將迎來轉捩點。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"먼 훗날, 냉정한 역사의 평가에 한 치에 부끄러움이 없도록.","JPN":"遠い未来、冷静な歴史の評価に一切恥じることのないように。","ENG":"So that in the future, there will be no shame in the cynical records of history.","TWN":"在遙遠的未來，面對冷靜的歷史評價時，不會有一絲羞愧。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"모든 경관은 이 작전에 만전을 기해주길 바라네.","JPN":"全警官はこの作戦に万全を期してくれ。","ENG":"I expect all officers to do their best in this operation.","TWN":"希望所有警員都能全力以赴完成這次任務。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자, 그러니 모든 경관은…….","JPN":"さあ、これより全警官は……","ENG":"So, I ask all officers...","TWN":"好，那麼我要求所有警員……"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L29_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>총성</color>이 울리면 진입하도록.","JPN":"<color=#ffd34c>銃声</color>が鳴り次第、突入するように。","ENG":"to enter at the sound of the <color=#ffd34c>gunshot</color>.","TWN":"<color=#ffd34c>槍聲</color>響起後就立刻開始行動。"},"stage":{"bg":"UNDER","bgm":"THEMA_CS_ORCHESTRA","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"자네의 연기는 훌륭했지만, 런던에서 발생하는 모든 정보는 내 손아귀에 안에 있다네.","JPN":"君の演技は素晴らしかったが、ロンドンで発生しているすべての情報は私の手の内にあるのだ。","ENG":"I applaud your acting, but all the information about what happens in London is in the palm of my hand.","TWN":"你的演技很出色，但倫敦發生的所有資訊都在我的掌握之中。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"예를 들면, 자네가 사칭하고 있는 그 교회는 이제 런던 지도에 존재하지 않아.","JPN":"例えば、君が名乗ったその教会は、もうロンドンの地図には存在しない。","ENG":"For instance, the church you are impersonating no longer exists on the London map.","TWN":"比如，你假冒的那座教堂現在已經不在倫敦地圖上了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"며칠 전에 폭동에 휘말려 붕괴되어 버렸으니까.","JPN":"数日前に暴動に巻き込まれて崩壊してしまったんだ。","ENG":"It collapsed after being caught up in a riot a few days ago.","TWN":"因為幾天前它就在暴動中被摧毀了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 자네는 누구일까?","JPN":"だとすれば、君は誰なのか？","ENG":"So, who are you?","TWN":"那麼你是誰呢？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"지금 내가 생각하고 있는 그 여배우가 맞을까?","JPN":"今、私が考えているあの女優で合っているのか？","ENG":"Are you the actress that comes to my mind right away?","TWN":"是我現在想的那個女演員對嗎？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SISTER_PRYDWEN_NPC_NULL","text":{"KOREA":"……큭!","JPN":"……くっ！","ENG":"...Kgh!","TWN":"……咳！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SISTER_PRYDWEN_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"이거 무척이나 궁금하군. 그 남자에게 있어, 자네는 대체 어떤 의미지?","JPN":"これはとても興味深い。あの男にとって、君はいったいどういう意味を持っているのだ？","ENG":"I'm very curious. Who are you to that man?","TWN":"這真是讓人好奇。對那個男人來說，你到底表示什麼？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"자네를 죽이면, 그 남자는 과연 무슨 표정을 지을까?","JPN":"そして君を殺せば、あの男はどんな顔をするだろうか？","ENG":"If you die, what kind of expression will he make?","TWN":"如果殺了你，那個人會露出什麼表情呢？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"어디 확인해보게, 대령.","JPN":"確認してみよう、大佐。","ENG":"Let's find out, Colonel.","TWN":"上校，來看看吧。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L46_1","type":"dialog","speaker":"MORAN_SWANSONG_NPC_NULL","text":{"KOREA":"알겠습니다.","JPN":"承知しました。","ENG":"Yes, sir.","TWN":"遵命。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"크헉……!?","JPN":"カハッ……！？","ENG":"Krrgh...?!","TWN":"呃……？！"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L2_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"대령! <color=#ffd34c>존 왓슨</color> 대령……! ","JPN":"大佐！　<color=#ffd34c>ジョン・ワトソン</color>大佐……！ ","ENG":"Colonel! Colonel <color=#ffd34c>John Watson</color>...!","TWN":"上校！<color=#ffd34c>約翰·華生</color>上校……！"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"자네 지금 이게 무슨 짓인가……!","JPN":"いったい何の真似だ……！","ENG":"What are you doing...?!","TWN":"你現在這是幹什麼……！"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"……삼 년이야.","JPN":"……三年だ。","ENG":"...Three years.","TWN":"……三年了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"런던에서 그림자 사태가 발생한 것도. 그간 네놈 밑에서 온갖 더러운 짓을 도맡았던 것도.","JPN":"ロンドンでシャドウ事変が発生したのも。今まで貴様の下であらゆる汚い仕事を受け持ったのも。","ENG":"Since London's Shadow incident. And working under you, doing all your dirty work.","TWN":"從倫敦發生暗影事件開始，我一直在你手下做各種骯髒的事情。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"오직 이 순간을 위해, 삼 년이라는 시간을 버틸 수 있었지.","JPN":"ただこの瞬間のために、三年という時間を耐えることができた。","ENG":"I was able to endure these three years, just for this moment.","TWN":"為了這一刻，我忍受了三年的時間。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"하아, 하아……!","JPN":"はあ、はあ……！","ENG":"*Huff* *Huff*","TWN":"咳，咳……！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그림자 사태라고? 그렇다면 설마 자네……?","JPN":"シャドウ事変？　ということは、まさか君……？","ENG":"Shadow incident? Then, you are...?","TWN":"暗影事件？那麼說你……？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"크윽……! 설마 숙적의 함정인가……!?","JPN":"うぐっ……！　まさか宿敵の罠なのか……！？","ENG":"Kgh...! You can't be the nemesis' trap...!","TWN":"呃咳……！難道是宿敵的陷阱……！?"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 대체 어디부터……?","JPN":"だが、いったいどこから……？","ENG":"Since when...?","TWN":"但到底從哪裡開始……？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"모두 움직이지 마! 이 사원에 있는 사교도들을 전부 현행범으로 체포해!","JPN":"全員動くな！　この寺院にいる邪教徒を全員現行犯で逮捕する！","ENG":"Freeze! Arrest all the cultists in this temple!","TWN":"都不要動！逮捕這個修道院裡所有的邪教徒！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L22_1","type":"dialog","speaker":"POLICE_SWANSONG_NPC_NULL","text":{"KOREA":"심야의 살인마를 잡을 수 있는 마지막 기회다! 아무리 사소한 증거물이라도 놓치지 마라!","JPN":"深夜の殺人鬼を捕まえられる最後のチャンスだ！　どんな些細な証拠品も見逃すな！","ENG":"It's our last chance to catch the Midnight Killer! Don't miss any evidence, no matter how trivial!","TWN":"這是抓住午夜殺人魔的最後機會！無論多麼微小的證據都不要放過！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLICE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_MAN","text":{"KOREA":"마기스텔 템프리께서 총상을 입으셨다!","JPN":"マギステル・テンプリ様が銃傷を負われた！","ENG":"The Magister Templi has been shot!","TWN":"神殿主中槍了！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_MAN","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L28_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_MAN","text":{"KOREA":"경찰이 사원을 습격했다! 어서 니그레도를 해방시켜!","JPN":"警察が寺院を襲撃した！　早くニグレドを解放しろ！","ENG":"The police have ambushed the temple! Release the Nigredos!","TWN":"是員警！快放出尼格列多！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_MAN","text":{"KOREA":"마물을 풀어서라도 사제님을 지켜야……!","JPN":"魔物を野放しにしてでも司祭様を守らないと……！","ENG":"Bring in the monsters to protect the priest–!","TWN":"即使放出怪物也要保護祭司大人……！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CULTIST_SWANSONG_NPC_MAN","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CULTIST_SWANSONG_NPC_MAN","text":{"KOREA":"으헉!!","JPN":"ぐはっ！！","ENG":"Gah!!","TWN":"呃呵！！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"다행히 늦지 않게 도착했군, 친구.","JPN":"間に合ってよかった、友よ。","ENG":"You arrived just in time, my friend.","TWN":"幸好沒有來遲，朋友。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"수고했네. 지금까지 고생 많았어. 오랜 벗이여.","JPN":"お疲れ。今までご苦労だったな、旧友。","ENG":"Great work. It must have been an agonizing three years, my old friend.","TWN":"做得好。這段時間你受苦了。老朋友啊。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그리고 이제 끝이라네.","JPN":"そしてもう終わりだ。","ENG":"But it's all over now.","TWN":"而且現在結束了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"순순히 네놈의 패배를 인정하시지, 모리어티 교수.","JPN":"素直に貴様の敗北を認めろ、モリアーティ教授。","ENG":"Admit your defeat, Professor Moriarty.","TWN":"乖乖承認你的失敗吧，莫里蒂教授。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그렇게 된 거군…….","JPN":"ふふ、そういうことか……","ENG":"Haha, so this was your plan...","TWN":"呵呵，原來是這樣啊……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"설마 <color=#ffd34c>대령</color>이 자네가 미리 심어둔 밀정일 줄이야…….","JPN":"まさか<color=#ffd34c>大佐</color>が君の密偵だったとは……","ENG":"I would've never imagined that the <color=#ffd34c>Colonel</color> would be the spy...","TWN":"我從未懷疑過<color=#ffd34c>上校</color>是你提前安插的間諜……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"간단한 이야기라네. 교수","JPN":"簡単な話だ、教授。","ENG":"It's elementary, my dear Professor.","TWN":"這很簡單，教授。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L47_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"삼 년 전, 런던에서 발생한 그림자 사태는 우리의 완전한 패배였지.","JPN":"三年前、ロンドンでのシャドウ事変は完全に私たちの負けだったよ。","ENG":"Three years ago, it was our utter defeat during the Shadow incident in London.","TWN":"三年前，倫敦發生的暗影事件是我們徹底的失敗。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"세 자릿수의 사상자가 발생했고, 런던의 이능력자가 차별받는 시발점이 되어버렸으니까.","JPN":"三桁台の死傷者が発生し、ロンドンの異能力者が差別されるきっかけになったからな。","ENG":"Casualties were in the hundreds, and it was the start of the discrimination against Supernaturals.","TWN":"造成了三位數的傷亡，並且成為了倫敦超能力者被歧視的起點。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래서 우리는 삼 년 전부터 그 사태의 배후에 있었던 네놈을 무너뜨릴 계획을 세웠어.","JPN":"だから私たちはこの三年間、あの事変の背後にいた貴様を潰す計画を立てたのだ。","ENG":"So, we devised a plan to defeat you, who was behind it three years ago.","TWN":"所以我們從三年前就開始計畫要推翻你這個事件背後的黑手。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"바로 지금처럼. 가장 중요한 순간에 네놈의 허를 찌를 수 있도록 말이야.","JPN":"今みたいに。もっとも重要な瞬間に貴様の不意をつくことができるように。","ENG":"It was done so that we could catch you off guard when it was most important.","TWN":"就像現在這樣。在最關鍵的時刻給你致命一擊。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"이거 완전히 자네 손바닥에서 놀아났군.","JPN":"これは、完全に君に弄ばれてしまった。","ENG":"So I've been played all this time.","TWN":"這一切完全是在你的掌控之中啊。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"자네의 조수는 결혼 후, 이 도시를 떠났다고 들었는데…… 거짓 정보였나.","JPN":"君の助手は結婚後、この都市を去ったと聞いたが……偽の情報だったのか。","ENG":"I heard your assistant left town after he got married... Was that information false?","TWN":"我聽說你的助手結婚離開了這座城市……原來是假的消息。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래. 나와 달리 내 벗은 대중들에게 얼굴이 노출되지 않았으니까.","JPN":"ああ。私と違って旧友は大衆に顔が知られていなかったからな。","ENG":"It was. Because unlike me, my friend here hadn't been exposed to the public.","TWN":"是啊。和我不同，我的朋友沒有在公眾面前露過面。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"동시에 사격 실력도 제법 뛰어나니, 군인을 선호하는 네놈의 측근으로 제격이었겠지.","JPN":"そのうえ射撃の腕も素晴らしい。軍人を好む貴様の側近には持って来いだったのだろう。","ENG":"And being an excellent sharpshooter, he was a perfect fit for you as you preferred soldiers.","TWN":"同時射擊能力也相當出色，作為你偏愛軍人的親信再合適不過了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 네놈 역시 만만한 사람은 아니었어.","JPN":"もちろん、貴様もまた容易い相手ではなかった。","ENG":"But then again, you weren't so easy.","TWN":"當然，你也不是個簡單的人物。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"의심을 사지 않기 위해, 내 벗은 네놈이 시키는 궂은 일을 도맡아왔으니까.","JPN":"怪しまれないために、私の旧友は貴様が指示する汚れ仕事を引き受けざるを得なかった。","ENG":"In order to not raise any suspicion, my friend had to do all your dirty work.","TWN":"為了不引起懷疑，我的朋友一直在替你做那些髒活。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 모든 것이 맞아 떨어진 결과, 네놈은 이렇게 땅바닥을 뒹굴게 된 거지.","JPN":"だがすべてが嚙み合った結果、貴様はこうやって地に落ちたってわけだ。","ENG":"And with everything falling into place, you are now rolling in the dirt as a result.","TWN":"但隨著一切就緒，你也只能接受現在這樣的結果了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"자, 이제 얌전히 법의 심판을 받도록 해. 제임스 모리어티.","JPN":"さあ、大人しく法の裁きを受けるといい。ジェームス・モリアーティ。","ENG":"Now, it's time you face the law for your misdeeds, James Moriarty.","TWN":"好了，現在乖乖接受法律的制裁吧，詹姆斯·莫里蒂。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_CA_SWAN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_04"},{"id":"L10_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"법의 심판이라고? 재미있군.","JPN":"法の裁き？　面白いな。","ENG":"The law? Interesting.","TWN":"法律的制裁？有趣。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그렇다면 자네의 소중한 파트너는 어떤가?","JPN":"だったら、君の大事なパートナーはどうなる？","ENG":"What about your precious partner?","TWN":"那麼你珍貴的搭檔怎麼辦？"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"살인, 방화, 마약 밀매…… 지난 삼 년간, 내 지시로 온갖 범죄를 저지르고 말았네만.","JPN":"殺人に放火、麻薬の密輸……三年間、私の指示で様々な犯罪を犯してきたのだ。","ENG":"Murder, arson, drug smuggling... For the last three years, he has also committed all manners of crime under my order.","TWN":"殺人、縱火、販毒……過去三年裡，我指使他犯下了各種罪行。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"물론, 자네의 그 훌륭한 <color=#ffd34c>계획</color>으로 인해서 말이지.","JPN":"もちろん、君のその素晴らしい<color=#ffd34c>計画</color>のせいでね。","ENG":"Of course, all due to your brilliant <color=#ffd34c>plan</color>.","TWN":"當然，這都是因為你那出色的<color=#ffd34c>計畫</color>。"},"stage":{"bg":"CORRIDOR_08","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"이거 소감이 궁금하군.","JPN":"感想が気になるものだ。","ENG":"I'm curious as to how you feel about all this.","TWN":"我很好奇你的感想。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"어떤가? 자신의 벗을 손수 범죄자로 만들어 버린 기분이?","JPN":"どうだ？　自分の友人を自分の手で犯罪者にしてしまった気分は。","ENG":"What is it like? To have turned your friend into a criminal yourself?","TWN":"感覺如何？親手把自己的朋友變成罪犯的感覺？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"닥쳐, 이건 내가 원해서 선택한 일이야!","JPN":"黙れ！　これは俺が自ら望んでしたことだ！","ENG":"Shut up. I chose to do it because I wanted to!","TWN":"閉嘴，這是我自己選擇的事情！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L18_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"나 역시 모든 일이 끝나면, 법의 심판을 받겠다!","JPN":"俺もすべてが終われば、裁きを受ける！","ENG":"I'll also receive my punishment after all this is over!","TWN":"等一切結束後，我也會接受法律的制裁！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"하지만 그전에 네놈과 그 복수귀를 나란히 사형대에 올려놓는 게 먼저야!","JPN":"だがその前に、貴様とあの復讐鬼を死刑台に上がらせるのが先だ！","ENG":"But before that, putting you and that Revenger on death row is first!","TWN":"但在那之前，先要把你和那個復仇鬼一起送上斷頭臺！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"원하는 것이라…….","JPN":"自ら望んで、か……","ENG":"So, you wanted to do it...","TWN":"你想要的東西……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"<color=#ffd34c>그대가 원하는 바를 해라. 그것이 곧 그대의 법이다.</color>","JPN":"<color=#ffd34c>汝の欲することを為せ、それが汝の法とならん。</color>","ENG":"<color=#ffd34c>Do what thou wilt. For it shall be thy law.</color>","TWN":"<color=#ffd34c>行汝欲行之事，此為律法之全部。</color>"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그러니 자네도 알고 있을 텐데, 숙적?","JPN":"君もわかっているはずだろう、宿敵？","ENG":"I’m sure you know this too, my nemesis.","TWN":"所以你也明白的，對吧，宿敵？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"내가 진짜 원하는 것은 나의 하찮은 목숨의 보전 따위가 아니라는 걸 말이야.","JPN":"私が本当に望むものとは、たかが自分の命を守るなどのくだらないものではないということを。","ENG":"What I truly want is not preserving my worthless life.","TWN":"我真正想要的，並不是保全我這卑微的性命。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"……뭐라고?","JPN":"……何だと？","ENG":"...What?","TWN":"……你說什麼？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"직접 나서는 건, 취향이 아니지만 어쩔 수 없지.","JPN":"直接表に出るのは、あまり好きではないが、仕方ない。","ENG":"It's not my preference to step forward, but I'll have to make an exception.","TWN":"雖然不喜歡親自出面，但也沒辦法。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애, 애버라인……!","JPN":"あ、アバーライン……！","ENG":"A-Abberline...!","TWN":"艾、艾伯林……！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완……!","JPN":"スワン……！","ENG":"Swan...!","TWN":"史旺……！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 그 표정을 보니, 내 예상이 맞는 것 같군.","JPN":"ふふ、君がそんな顔をするとは。私の予想が当たっていたようだな。","ENG":"Haha. Seeing that face, my prediction was right.","TWN":"呵呵，看你的表情，我的預想似乎是對的。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"아무래도 이 가련한 여배우가 자네에게 있어서, 무척 중요한 사람인 모양이야.","JPN":"どうやらこの可憐な女優が、君にとってとても大切な人のようだ。","ENG":"It seems that this poor actress is someone terribly important to you.","TWN":"看來這個可憐的女演員對你來說，是個非常重要的人。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L35_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그렇지 않나, 숙적?","JPN":"そうだろう？　宿敵。","ENG":"Isn’t that right?","TWN":"不是嗎，宿敵？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"쏘지 말게, 왓슨!","JPN":"撃つな、ワトソン！","ENG":"Don't shoot, Watson!","TWN":"別開槍，華生！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L40_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"정신 차려, 친구! 저 아이를 오랫동안 찾아왔던 건 알아! 하지만 결단해야 해!","JPN":"しっかりしろ、友！　長い間あの子を捜してきたことはわかる！　だが、決断しなければならない！","ENG":"Snap out of it! I know you have been searching for her for a long time! But you must choose!","TWN":"振作點，朋友！我知道你找那個孩子很久了！但你必須做出決定！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"이대로라면, 모리어티는 저 아이를 인질 삼아서 또 다시 여길 빠져나갈지도 몰라!","JPN":"このままだと、モリアーティはあの子を人質にまたここから抜け出すかもしれないんだぞ！","ENG":"If we let him live, Moriarty will use her as a hostage to try to escape!","TWN":"照這樣下去，莫里蒂可能會利用那個孩子作為人質，再次從我們眼皮子底下逃走！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"나를 믿게. 늘 그랬듯 말이야.","JPN":"私のことを信じるのだ。いつもそうしてきたようにな。","ENG":"Trust me. Like you always have.","TWN":"相信我吧，就像以前一樣。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L45_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"WATSON_SWANSONG_NPC_NULL","text":{"KOREA":"좋아, 알겠네.","JPN":"よし、わかった。","ENG":"All right.","TWN":"好，知道了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"WATSON_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"으, 으윽……!","JPN":"う、ううっ……！","ENG":"N-ngh...!","TWN":"呃……呃……！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"어떤가, <color=#ffd34c>지팡이</color>라네.","JPN":"どうだ、<color=#ffd34c>杖</color>だ。","ENG":"What do you think? It is the <color=#ffd34c>Staff</color>.","TWN":"怎麼樣，這是<color=#ffd34c>拐杖</color>。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"황금 새벽회가 가지고 있던 강력한 마도구 중 하나지.","JPN":"黄金の暁団が持っていた強力な魔道具の一つだ。","ENG":"It's one of the potent Curios owned by the Golden Dawn.","TWN":"這是黃金黎明會擁有的強力魔導具之一。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"이 정도 위력이라면, 자네들은 물론 시설에 남은 모든 증거물도 깨끗하게 사라질 거야.","JPN":"この程度の威力なら、君たちはもちろん、施設に残っているすべての証拠物もきれいさっぱり消えるはず。","ENG":"With this amount of power, it can wipe everything off clean. You and all the evidence left in this facility.","TWN":"如果有這種威力的話，不僅是你們，連這裡留下的所有證據都會徹底消失。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"어리석군. 그걸 쓰면 자네 역시 무사하지 못할 텐데?","JPN":"愚かだな。それを使えば、君も無事では済まないはずだが。","ENG":"How shortsighted. You won't be safe either if you use that.","TWN":"真是愚蠢。使用那種力量，你自己也不可能安然無恙吧？"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"후후, 어차피 내 목숨도 이제 얼마 남지 않은 모양이거든.","JPN":"ふふ、どうせ私の命も残りわずかのようだからな。","ENG":"Haha. My life is running out anyway.","TWN":"呵呵，反正我的命也所剩無幾了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"이 세계에 금빛 새벽이 내리는 것을 직접 마주하지 못하는 것이 아쉽지만.","JPN":"この世界に黄金の暁が訪れるのを直接見ることができないのは残念だが。","ENG":"It is a shame that I won't be able to witness what the golden dawn will bring down to this world, but.","TWN":"雖然無法親眼見證這世界的金色黎明降臨，真是遺憾。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"이제 천사의 강림까지 남은 제물은 단 하나.","JPN":"もはや天使の降臨まで残りの生贄はあと一人。","ENG":"There is only one sacrificial offering left for the angel's descent.","TWN":"現在距離天使降臨只剩下最後一個祭品了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"마그눔 오푸스. 내가 만든 최후의 걸작, 심야의 살인마가 더는 방해받지 않도록.","JPN":"マグヌム・オプス。私が作った最後の傑作、深夜の殺人鬼がこれ以上邪魔されないように。","ENG":"Magnum Opus. So the Midnight Killer, my final masterpiece, will no longer be bothered.","TWN":"偉大傑作在上。這是我最後的傑作。這樣，午夜殺人魔也將不再受到干擾。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"여기 있는 모든 이들을 길동무로 삼아야겠네.","JPN":"ここにいるすべての者を道連れにしよう。","ENG":"I'll take everyone here down with me.","TWN":"看來這裡的所有人都要與我陪葬了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인, 나는 괜찮아요……!","JPN":"アバーライン、私は大丈夫です……！","ENG":"Abberline, I'm all right...!","TWN":"艾伯林，我沒事……！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"그러니까 어서……!","JPN":"だから早く……！","ENG":"So, hurry...!","TWN":"所以，快……！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS2"},"R":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 어디 해볼 테면 해보게.","JPN":"ああ、やれるならやってみろ。","ENG":"Let's see if you have the guts to do it.","TWN":"很好！你可以試試看。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"공공의 이익을 위해서라면, 나는 얼마든지 내 죽음을 받아들이겠다고 결심했으니까.","JPN":"公共の利益のためなら、私はいくらでも自分の死を受け入れると決めたからな。","ENG":"Because I'm prepared to accept my death if it is for the public good.","TWN":"為了更大的利益，我已經決定隨時接受我的死亡。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"역시……. 자네만큼 날 재밌게 해주는 사람은 없군.","JPN":"やはり……君ほど私を楽しませてくれる人はいないよ。","ENG":"Yes... There is no one who entertains me as much as you.","TWN":"果然……沒有人能比你更讓我開心了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORIARTY_SWANSONG_NPC_NULL","text":{"KOREA":"그럼, 사양하지 않겠네.","JPN":"では、遠慮せずにいこう。","ENG":"Then, I won't say no.","TWN":"那，我就不客氣了。"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORIARTY_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"안 돼, 애버라인……!!","JPN":"ダメ、アバーライン……！！","ENG":"No! ABBERLINE...!!","TWN":"不要，艾伯林……！！"},"stage":{"bg":"CORRIDOR_08","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};